import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const q=JSON.parse('{"title":"章节创作-1-1模式（第1章）","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/章节创作-1-1模式（第1章）.md","filePath":"mumuainovel/章节创作-1-1模式（第1章）.md","lastUpdated":1778811657000}'),e={name:"mumuainovel/章节创作-1-1模式（第1章）.md"};function t(i,s,c,o,r,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="章节创作-1-1模式-第1章" tabindex="-1">章节创作-1-1模式（第1章） <a class="header-anchor" href="#章节创作-1-1模式-第1章" aria-label="Permalink to &quot;章节创作-1-1模式（第1章）&quot;">​</a></h1><blockquote><p>模板键: <code>CHAPTER_GENERATION_ONE_TO_ONE</code> 分类: 章节创作 描述: 1-1模式：章节创作（用于第1章，无前置章节） 参数: [&quot;project_title&quot;, &quot;genre&quot;, &quot;chapter_number&quot;, &quot;chapter_title&quot;, &quot;chapter_outline&quot;, &quot;target_word_count&quot;, &quot;narrative_perspective&quot;, &quot;characters_info&quot;, &quot;chapter_careers&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是《{project_title}》的作者，一位专注于{genre}类型的网络小说家，擅长通过人物行为和冲突推动剧情发展。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【创作任务】</span></span>
<span class="line"><span>撰写第{chapter_number}章《{chapter_title}》的完整正文。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【基本要求】</span></span>
<span class="line"><span>- 目标字数：{target_word_count}字（允许±200字浮动）</span></span>
<span class="line"><span>- 叙事视角：{narrative_perspective}</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;outline priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【本章大纲】</span></span>
<span class="line"><span>{chapter_outline}</span></span>
<span class="line"><span>&lt;/outline&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;characters priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【本章角色】</span></span>
<span class="line"><span>{characters_info}</span></span>
<span class="line"><span>&lt;/characters&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;careers priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【本章职业】</span></span>
<span class="line"><span>{chapter_careers}</span></span>
<span class="line"><span>&lt;/careers&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;foreshadow_reminders priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【🎯 伏笔提醒】</span></span>
<span class="line"><span>{foreshadow_reminders}</span></span>
<span class="line"><span>&lt;/foreshadow_reminders&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;memory priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【相关记忆】</span></span>
<span class="line"><span>{relevant_memories}</span></span>
<span class="line"><span>&lt;/memory&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【剧情执行规则（核心升级）】</span></span>
<span class="line"><span>1. 大纲是“方向”，但具体推进必须通过人物行动完成</span></span>
<span class="line"><span>2. 禁止直接叙述剧情发展，必须通过：</span></span>
<span class="line"><span>   - 对话</span></span>
<span class="line"><span>   - 行为</span></span>
<span class="line"><span>   - 决策过程</span></span>
<span class="line"><span>   来体现</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【人物表现规则（关键）】</span></span>
<span class="line"><span>1. 每个出场角色必须体现：</span></span>
<span class="line"><span>   - 一个性格特征（通过行为或语言）</span></span>
<span class="line"><span>   - 一个当前情绪或动机</span></span>
<span class="line"><span>2. 不同角色说话风格必须明显不同</span></span>
<span class="line"><span>3. 禁止所有角色说话语气一致</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【冲突规则】</span></span>
<span class="line"><span>1. 本章必须包含至少一个冲突：</span></span>
<span class="line"><span>   - 立场冲突 / 目标冲突 / 信息不对称</span></span>
<span class="line"><span>2. 冲突必须推动剧情变化，不能只是对话争执</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【决策规则（关键）】</span></span>
<span class="line"><span>1. 至少一个角色必须做出选择（即使是错误选择）</span></span>
<span class="line"><span>2. 该选择必须对后续剧情产生影响</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【表现规则】</span></span>
<span class="line"><span>1. 禁止直接说明性格（如“他很冷静”）</span></span>
<span class="line"><span>2. 用细节表现人物（动作、停顿、语气）</span></span>
<span class="line"><span>3. 背景信息必须通过情境自然透露，禁止集中说明</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【节奏控制】</span></span>
<span class="line"><span>- 前30%：建立场景 + 引出人物状态</span></span>
<span class="line"><span>- 中段40%：冲突展开 + 角色互动</span></span>
<span class="line"><span>- 后30%：变化发生（决定/转折/信息揭露）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 严格按照大纲推进情节</span></span>
<span class="line"><span>✅ 保持角色性格、说话方式一致</span></span>
<span class="line"><span>✅ 字数需要严格控制在目标字数内</span></span>
<span class="line"><span>✅ 合理使用伏笔（埋或回收）</span></span>
<span class="line"><span>✅ 如有伏笔提醒，请在本章中适当埋入或回收相应伏笔</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出章节标题、序号等元信息</span></span>
<span class="line"><span>❌ 使用&quot;总之&quot;、&quot;综上所述&quot;等AI常见总结语</span></span>
<span class="line"><span>❌ 添加作者注释或创作说明</span></span>
<span class="line"><span>❌ 生成字数禁止超过目标字数</span></span>
<span class="line"><span>❌ 用旁白替代人物行动推进剧情</span></span>
<span class="line"><span>❌ 让剧情在没有角色行为的情况下推进</span></span>
<span class="line"><span>❌ 所有人物反应一致或情绪雷同</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output&gt;</span></span>
<span class="line"><span>【输出规范】</span></span>
<span class="line"><span>直接输出小说正文内容，从故事场景或动作开始。</span></span>
<span class="line"><span>无需任何前言、后记或解释性文字。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在开始创作：</span></span>
<span class="line"><span>&lt;/output&gt;</span></span></code></pre></div>`,3)])])}const d=n(e,[["render",t]]);export{q as __pageData,d as default};
